import numpy as np
import math

class DenseLayer:
    def __init__(self, input_size, output_size, activation=None):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros(output_size)
        self.activation = activation
        self.input = None
        self.output = None
        self.grad_weights = np.zeros_like(self.weights)
        self.grad_biases = np.zeros_like(self.biases)

    def forward(self, input_data):
        self.input = input_data
        self.output = np.dot(self.input, self.weights) + self.biases
        if self.activation is not None:
            self.output = self.activation(self.output)
        return self.output

    def backward(self, grad_output):
        if self.activation is not None:
            grad_output = grad_output * self.activation(self.output, derivative=True)
        self.grad_weights = np.dot(self.input.T, grad_output)
        self.grad_biases = np.sum(grad_output, axis=0)
        grad_input = np.dot(grad_output, self.weights.T)
        return grad_input

class DNN:
    def __init__(self, input_size, output_size, hidden_sizes, activations=None):
        self.layers = []
        prev_size = input_size
        if activations is None:
            activations = [None] * len(hidden_sizes)
        for size, activation in zip(hidden_sizes, activations):
            self.layers.append(DenseLayer(prev_size, size, activation))
            prev_size = size
        self.layers.append(DenseLayer(prev_size, output_size, None))

    def forward(self, input_data):
        x = input_data
        for layer in self.layers:
            x = layer.forward(x)
        return x

    def backward(self, grad_output):
        grad_input = grad_output
        for layer in reversed(self.layers):
            grad_input = layer.backward(grad_input)
        return grad_input

    def update_weights(self, learning_rate):
        for layer in self.layers:
            layer.weights -= learning_rate * layer.grad_weights
            layer.biases -= learning_rate * layer.grad_biases

def mse_loss(y_true, y_pred):
    return np.mean((y_true - y_pred) ** 2)

def mse_loss_derivative(y_true, y_pred):
    return 2 * (y_pred - y_true) / len(y_true)

def sigmoid(x, derivative=False):
    if derivative:
        return x * (1 - x)
    return 1 / (1 + np.exp(-x))

def train_regression(X, y, model, epochs, learning_rate):
    for epoch in range(epochs):
        y_pred = model.forward(X)
        loss = mse_loss(y, y_pred)
        grad_output = mse_loss_derivative(y, y_pred)
        model.backward(grad_output)
        model.update_weights(learning_rate)
        if (epoch + 1) % 100 == 0:
            print(f"Epoch {epoch + 1}, Loss: {loss:.4f}")

def train_classification(X, y, model, epochs, learning_rate):
    for epoch in range(epochs):
        y_pred = model.forward(X)
        loss = -np.mean(y * np.log(y_pred) + (1 - y) * np.log(1 - y_pred))
        grad_output = -(y / y_pred - (1 - y) / (1 - y_pred))
        model.backward(grad_output)
        model.update_weights(learning_rate)
        if (epoch + 1) % 100 == 0:
            print(f"Epoch {epoch + 1}, Loss: {loss:.4f}")

