import numpy as np
import math

class Layer:
    def __init__(self, input_size, output_size, activation):
        self.weights = np.random.randn(output_size, input_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros((output_size, 1))
        self.activation = activation
        self.activation_derivative = self.get_activation_derivative(activation)
        self.input = None
        self.output = None
        self.delta = None

    def forward(self, input):
        self.input = input
        self.output = self.activation(np.dot(self.weights, self.input) + self.biases)
        return self.output

    def backward(self, delta_next, learning_rate):
        self.delta = np.multiply(np.dot(delta_next.T, self.weights).T, self.activation_derivative(self.output))
        self.weights -= learning_rate * np.dot(self.delta, self.input.T)
        self.biases -= learning_rate * self.delta
        return self.delta

    def get_activation_derivative(self, activation):
        if activation == self.sigmoid:
            return lambda x: x * (1 - x)
        elif activation == self.tanh:
            return lambda x: 1 - x ** 2
        elif activation == self.relu:
            return lambda x: 1. * (x > 0.)
        else:
            raise ValueError("Activation function not supported")

    @staticmethod
    def sigmoid(x):
        return 1 / (1 + np.exp(-x))

    @staticmethod
    def tanh(x):
        return np.tanh(x)

    @staticmethod
    def relu(x):
        return np.maximum(0, x)

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_sizes, activations):
        self.layers = []
        self.input_size = input_size
        self.output_size = output_size

        for i in range(len(hidden_sizes)):
            if i == 0:
                self.layers.append(Layer(input_size, hidden_sizes[i], activations[i]))
            else:
                self.layers.append(Layer(hidden_sizes[i-1], hidden_sizes[i], activations[i]))
        self.layers.append(Layer(hidden_sizes[-1], output_size, activations[-1]))

    def forward(self, input):
        for layer in self.layers:
            input = layer.forward(input)
        return input

    def backward(self, target, learning_rate):
        delta = self.layers[-1].activation_derivative(self.layers[-1].output) * (self.layers[-1].output - target)
        for layer in reversed(self.layers):
            delta = layer.backward(delta, learning_rate)

    def train(self, X, y, epochs, learning_rate, batch_size=32):
        num_samples = X.shape[0]
        for epoch in range(epochs):
            for batch in range(0, num_samples, batch_size):
                batch_X = X[batch:batch+batch_size]
                batch_y = y[batch:batch+batch_size]
                output = self.forward(batch_X.T)
                self.backward(batch_y.T, learning_rate)
            if epoch % 10 == 0:
                print(f"Epoch {epoch}, Loss: {self.loss(X, y):.4f}")

    def loss(self, X, y):
        output = self.forward(X.T)
        return np.mean(np.square(output.T - y))

