import numpy as np

class Dense:
    def __init__(self, input_size, output_size, activation=None):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros(output_size)
        self.activation = activation
        self.input = None
        self.output = None
        self.delta = None

    def forward(self, inputs):
        self.input = inputs
        self.output = np.dot(self.input, self.weights) + self.biases
        if self.activation is not None:
            self.output = self.activation(self.output)
        return self.output

    def backward(self, prev_delta):
        if self.activation is not None:
            self.delta = prev_delta * self.activation(self.output, derivative=True)
        else:
            self.delta = prev_delta
        grad_w = np.dot(self.input.T, self.delta)
        grad_b = np.sum(self.delta, axis=0)
        return np.dot(self.delta, self.weights.T), grad_w, grad_b

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers=[]):
        self.layers = []
        self.layers.append(Dense(input_size, hidden_layers[0], activation=np.tanh))
        for i in range(len(hidden_layers) - 1):
            self.layers.append(Dense(hidden_layers[i], hidden_layers[i+1], activation=np.tanh))
        self.layers.append(Dense(hidden_layers[-1], output_size))

    def forward(self, inputs):
        for layer in self.layers:
            inputs = layer.forward(inputs)
        return inputs

    def backward(self, targets):
        delta = self.layers[-1].output - targets
        for layer in reversed(self.layers):
            delta, grad_w, grad_b = layer.backward(delta)
            layer.weights -= 0.01 * grad_w
            layer.biases -= 0.01 * grad_b

    def train(self, X, y, epochs=100):
        for _ in range(epochs):
            for i in range(len(X)):
                self.forward(X[i])
                self.backward(y[i])

