import numpy as np
import math

class Layer:
    def __init__(self, input_size, output_size, activation):
        self.weights = np.random.randn(output_size, input_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros((output_size, 1))
        self.activation = activation
        self.input = None
        self.output = None
        self.gradient_weights = np.zeros_like(self.weights)
        self.gradient_biases = np.zeros_like(self.biases)

    def forward(self, input_data):
        self.input = input_data
        self.output = self.activation(np.dot(self.weights, self.input) + self.biases)
        return self.output

    def backward(self, gradient):
        gradient_output = gradient * self.activation(self.output, True)
        self.gradient_weights = np.dot(gradient_output, self.input.T)
        self.gradient_biases = np.sum(gradient_output, axis=1, keepdims=True)
        gradient_input = np.dot(self.weights.T, gradient_output)
        return gradient_input

class ActivationFunction:
    @staticmethod
    def sigmoid(x, derivative=False):
        if derivative:
            return x * (1 - x)
        return 1 / (1 + np.exp(-x))

    @staticmethod
    def relu(x, derivative=False):
        if derivative:
            return np.where(x > 0, 1, 0)
        return np.maximum(0, x)

    @staticmethod
    def tanh(x, derivative=False):
        if derivative:
            return 1 - x ** 2
        return np.tanh(x)

class NeuralNetwork:
    def __init__(self, input_size, hidden_sizes, output_size):
        self.layers = []
        self.layers.append(Layer(input_size, hidden_sizes[0], ActivationFunction.relu))
        for i in range(1, len(hidden_sizes)):
            self.layers.append(Layer(hidden_sizes[i-1], hidden_sizes[i], ActivationFunction.relu))
        self.layers.append(Layer(hidden_sizes[-1], output_size, ActivationFunction.sigmoid))

    def forward(self, input_data):
        x = input_data
        for layer in self.layers:
            x = layer.forward(x)
        return x

    def backward(self, targets, learning_rate):
        gradient = (self.layers[-1].output - targets) * self.layers[-1].activation(self.layers[-1].output, True)
        for layer in reversed(self.layers):
            gradient = layer.backward(gradient)
        for layer in self.layers:
            layer.weights -= learning_rate * layer.gradient_weights
            layer.biases -= learning_rate * layer.gradient_biases

