import numpy as np
import math

class FullyConnectedLayer:
    def __init__(self, in_size, out_size, activation):
        self.weights = np.random.randn(out_size, in_size) * np.sqrt(2.0 / in_size)
        self.biases = np.zeros(out_size)
        self.activation = activation
        self.input = None
        self.output = None
        self.grad_weights = np.zeros_like(self.weights)
        self.grad_biases = np.zeros_like(self.biases)

    def forward(self, input_data):
        self.input = input_data
        self.output = self.activation.forward(np.dot(self.weights, self.input.T).T + self.biases)
        return self.output

    def backward(self, grad_output):
        grad_input = np.dot(grad_output, self.weights)
        self.grad_weights = np.dot(grad_output.T, self.input)
        self.grad_biases = np.sum(grad_output, axis=0)
        self.activation.backward(self.input, self.output, grad_output, self.grad_weights, self.grad_biases)
        return grad_input

class Activation:
    def __init__(self, name):
        self.name = name

    def forward(self, x):
        if self.name == 'relu':
            return np.maximum(0, x)
        elif self.name == 'sigmoid':
            return 1 / (1 + np.exp(-x))
        elif self.name == 'tanh':
            return np.tanh(x)
        else:
            raise ValueError(f'Unsupported activation function: {self.name}')

    def backward(self, input_data, output, grad_output, grad_weights, grad_biases):
        if self.name == 'relu':
            grad_output[output <= 0] = 0
        elif self.name == 'sigmoid':
            grad_output = grad_output * output * (1 - output)
        elif self.name == 'tanh':
            grad_output = grad_output * (1 - output ** 2)
        else:
            raise ValueError(f'Unsupported activation function: {self.name}')

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_sizes, activations):
        self.layers = []
        self.input_size = input_size
        self.output_size = output_size

        if len(hidden_sizes) != len(activations):
            raise ValueError('The number of hidden sizes must match the number of activations')

        prev_size = input_size
        for i, size in enumerate(hidden_sizes):
            layer = FullyConnectedLayer(prev_size, size, Activation(activations[i]))
            self.layers.append(layer)
            prev_size = size

        output_layer = FullyConnectedLayer(prev_size, output_size, Activation('linear'))
        self.layers.append(output_layer)

    def forward(self, input_data):
        output = input_data
        for layer in self.layers:
            output = layer.forward(output)
        return output

    def backward(self, output_grad):
        grad_input = output_grad
        for layer in reversed(self.layers):
            grad_input = layer.backward(grad_input)
        return grad_input

    def update_weights(self, learning_rate):
        for layer in self.layers:
            layer.weights -= learning_rate * layer.grad_weights
            layer.biases -= learning_rate * layer.grad_biases

