import numpy as np
import math

class Activations:
    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(0, x)

    def relu_derivative(self, x):
        return (x > 0) * 1.0

    def tanh(self, x):
        return np.tanh(x)

    def tanh_derivative(self, x):
        return 1 - x ** 2

class Layer:
    def __init__(self, input_size, output_size, activation_function):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2.0 / input_size)
        self.biases = np.zeros((1, output_size))
        self.activation_function = activation_function
        self.activation_derivative = self.get_activation_derivative(activation_function)
        self.inputs = None
        self.outputs = None
        self.errors = None

    def get_activation_derivative(self, activation_function):
        if activation_function == "sigmoid":
            return Activations().sigmoid_derivative
        elif activation_function == "relu":
            return Activations().relu_derivative
        elif activation_function == "tanh":
            return Activations().tanh_derivative

    def forward(self, inputs):
        self.inputs = inputs
        self.outputs = self.activation_function(np.dot(self.inputs, self.weights) + self.biases)
        return self.outputs

    def backward(self, output_errors, learning_rate):
        self.errors = output_errors * self.activation_derivative(self.outputs)
        weight_gradients = np.dot(self.inputs.T, self.errors)
        bias_gradients = np.sum(self.errors, axis=0, keepdims=True)
        self.weights -= learning_rate * weight_gradients
        self.biases -= learning_rate * bias_gradients
        return np.dot(self.errors, self.weights.T)

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layer_sizes, activation_function):
        self.layers = []
        self.activation_function = activation_function

        # Input layer
        self.layers.append(Layer(input_size, hidden_layer_sizes[0], self.activation_function))

        # Hidden layers
        for i in range(len(hidden_layer_sizes) - 1):
            self.layers.append(Layer(hidden_layer_sizes[i], hidden_layer_sizes[i + 1], self.activation_function))

        # Output layer
        self.layers.append(Layer(hidden_layer_sizes[-1], output_size, self.activation_function))

    def forward(self, inputs):
        for layer in self.layers:
            inputs = layer.forward(inputs)
        return inputs

    def backward(self, outputs, targets, learning_rate):
        errors = targets - outputs
        for layer in reversed(self.layers):
            errors = layer.backward(errors, learning_rate)
        return errors

def train_regression_model(X_train, y_train, X_val, y_val, hidden_layer_sizes, epochs, learning_rate):
    input_size = X_train.shape[1]
    output_size = y_train.shape[1]
    model = NeuralNetwork(input_size, output_size, hidden_layer_sizes, Activations().tanh)

    for epoch in range(epochs):
        outputs = model.forward(X_train)
        train_loss = np.mean((outputs - y_train) ** 2)
        model.backward(outputs, y_train, learning_rate)

        val_outputs = model.forward(X_val)
        val_loss = np.mean((val_outputs - y_val) ** 2)

        print(f"Epoch {epoch}: Train Loss: {train_loss:.4f}, Validation Loss: {val_loss:.4f}")

    return model

def train_classification_model(X_train, y_train, X_val, y_val, hidden_layer_sizes, epochs, learning_rate):
    input_size = X_train.shape[1]
    output_size = 1  # Binary classification
    model = NeuralNetwork(input_size, output_size, hidden_layer_sizes, Activations().sigmoid)

    for epoch in range(epochs):
        outputs = model.forward(X_train)
        train_loss = np.mean(-(y_train * np.log(outputs) + (1 - y_train) * np.log(1 - outputs)))
        model.backward(outputs, y_train, learning_rate)

        val_outputs = model.forward(X_val)
        val_loss = np.mean(-(y_val * np.log(val_outputs) + (1 - y_val) * np.log(1 - val_outputs)))

        train_acc = np.mean((outputs > 0.5) == y_train)
        val_acc = np.mean((val_outputs > 0.5) == y_val)

        print(f"Epoch {epoch}: Train Loss: {train_loss:.4f}, Train Acc: {train_acc:.4f}, Validation Loss: {val_loss:.4f}, Validation Acc: {val_acc:.4f}")

    return model

# Example usage for regression problem
