import numpy as np
import math

class NeuralNetworkLayer:
    def __init__(self, n_inputs, n_neurons, activation):
        self.weights = np.random.randn(n_inputs, n_neurons) * np.sqrt(2.0 / n_inputs)
        self.biases = np.zeros((1, n_neurons))
        self.activation = activation
        self.z = None
        self.a = None

    def forward(self, inputs):
        self.z = np.dot(inputs, self.weights) + self.biases
        self.a = self.activation(self.z)
        return self.a

    def backward(self, dA):
        dZ = dA * self.activation(self.z, derivative=True)
        dW = np.dot(self.a.T, dZ)
        dB = np.sum(dZ, axis=0, keepdims=True)
        return dZ, dW, dB

class NeuralNetwork:
    def __init__(self, layer_sizes, activations):
        self.layers = []
        for i in range(len(layer_sizes) - 1):
            self.layers.append(NeuralNetworkLayer(layer_sizes[i], layer_sizes[i+1], activations[i]))

    def forward(self, X):
        a = X
        for layer in self.layers:
            a = layer.forward(a)
        return a

    def backward(self, X, y, output_layer_loss_derivative):
        m = X.shape[0]
        a = self.forward(X)
        dA = output_layer_loss_derivative(a, y) / m

        for layer in reversed(self.layers):
            dZ, dW, dB = layer.backward(dA)
            dA = np.dot(dZ, layer.weights.T)

        return dW, dB

    def train(self, X, y, learning_rate, epochs, output_layer_loss, output_layer_loss_derivative):
        for epoch in range(epochs):
            dW, dB = self.backward(X, y, output_layer_loss_derivative)
            for i, layer in enumerate(self.layers):
                layer.weights -= learning_rate * dW[i]
                layer.biases -= learning_rate * dB[i]

# Example: Regression
X = np.random.randn(100, 5)
