import numpy as np

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers=1, hidden_size=64, activation_function='relu'):
        self.input_size = input_size
        self.output_size = output_size
        self.hidden_layers = hidden_layers
        self.hidden_size = hidden_size
        self.activation_function = activation_function

        self.weights = []
        self.biases = []

        self.initialize_weights()

    def initialize_weights(self):
        self.weights.append(np.random.randn(self.input_size, self.hidden_size))
        self.biases.append(np.zeros(self.hidden_size))

        for _ in range(self.hidden_layers - 1):
            self.weights.append(np.random.randn(self.hidden_size, self.hidden_size))
            self.biases.append(np.zeros(self.hidden_size))

        self.weights.append(np.random.randn(self.hidden_size, self.output_size))
        self.biases.append(np.zeros(self.output_size))

    def activate(self, x):
        if self.activation_function == 'relu':
            return np.maximum(0, x)
        elif self.activation_function == 'sigmoid':
            return 1 / (1 + np.exp(-x))
        else:
            raise ValueError('Invalid activation function')

    def forward(self, X):
        activations = [X]
        for i in range(self.hidden_layers + 1):
            z = np.dot(activations[-1], self.weights[i]) + self.biases[i]
            a = self.activate(z)
            activations.append(a)
        return activations[-1]

    def backward(self, X, y, learning_rate):
        activations = self.forward(X)
        deltas = [None] * (self.hidden_layers + 2)

        deltas[-1] = activations[-1] - y
        for i in reversed(range(self.hidden_layers + 1)):
            deltas[i] = np.dot(deltas[i + 1], self.weights[i].T) * self.activate(activations[i], derivative=True)

        for i in range(self.hidden_layers + 1):
            self.weights[i] -= learning_rate * np.outer(activations[i], deltas[i + 1])
            self.biases[i] -= learning_rate * deltas[i + 1]

    def train(self, X, y, epochs, learning_rate):
        for _ in range(epochs):
            for i in range(len(X)):
                self.backward(X[i], y[i], learning_rate)

