        self.biases = []
        self.initialize_weights_and_biases()

    def initialize_weights_and_biases(self):
        for i in range(len(self.layers) - 1):
            self.weights.append(np.random.randn(self.layers[i+1], self.layers[i]))
            self.biases.append(np.random.randn(self.layers[i+1], 1))

    def forward(self, inputs):
        outputs = inputs
        for i in range(len(self.layers) - 1):
            outputs = self.sigmoid(np.dot(self.weights[i], outputs) + self.biases[i])
        return outputs

    def backward(self, inputs, expected_outputs):
        outputs = self.forward(inputs)
        error = expected_outputs - outputs
        delta = error * self.derivative_sigmoid(outputs)
        for i in range(len(self.layers) - 2, -1, -1):
            self.weights[i] += np.dot(delta, self.forward(inputs).T)
            self.biases[i] += delta
            delta = np.dot(self.weights[i].T, delta) * self.derivative_sigmoid(self.forward(inputs))
        return error

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def derivative_sigmoid(self, x):
        return x * (1 - x)

    def train(self, inputs, expected_outputs, epochs, learning_rate):
        for epoch in range(epochs):
            error = self.backward(inputs, expected_outputs)
            if epoch % 100 == 0:
                print(f"Epoch {epoch}, Error: {np.mean(error)}")

